/**
 * Pick a verse to show for a break. A rotating counter (passed by the caller)
 * advances the verse each break. We walk by a stride that is coprime with the
 * verse count, so every verse is shown exactly once before any repeats, while
 * still jumping around (avoiding the same theme block back-to-back).
 * Deterministic given the counter, so re-renders don't reshuffle mid-break.
 */
const STRIDE = 17; // coprime with VERSES.length → full coverage, no early repeats
export function getVerseByIndex(counter: number): Verse {
  const idx = (((counter * STRIDE) % VERSES.length) + VERSES.length) % VERSES.length;
  return VERSES[idx];
}
